UPDATE sai_client_node rt, (
SELECT #{item.appId} AS app_id, #{item.hostId} AS host_id, #{item.maxConcurrent} AS max_concurrent, #{item.activeChats} AS active_chats, #{item.supportedProviders} AS supported_providers, #{item.labels} AS labels, #{item.expireDt} AS expire_dt
) tt SET rt.max_concurrent = tt.max_concurrent, rt.active_chats = tt.active_chats, rt.supported_providers = tt.supported_providers, rt.labels = tt.labels, rt.expire_dt = tt.expire_dt WHERE rt.app_id = tt.app_id AND rt.host_id = tt.host_id
